func solve(grid [][]int64, x int64, y int64, k int64) [][]int64 {
    m := len(grid)
    if m == 0 {
        return grid
    }
    n := len(grid[0])
    newGrid := make([][]int64, m)
    for i := 0; i < m; i++ {
        newGrid[i] = make([]int64, n)
        copy(newGrid[i], grid[i])
    }

    startRow := int(x)
    endRow := startRow + int(k) - 1
    startCol := int(y)
    endCol := startCol + int(k) - 1

    subRows := make([][]int64, k)
    for i := 0; i < k; i++ {
        subRows[i] = make([]int64, k)
        for j := 0; j < k; j++ {
            subRows[i][j] = newGrid[startRow+i][startCol+j]
        }
    }

    for i := 0; i < k/2; i++ {
        subRows[i], subRows[k-1-i] = subRows[k-1-i], subRows[i]
    }

    for i := 0; i < k; i++ {
        row := startRow + i
        for j := 0; j < k; j++ {
            newGrid[row][startCol+j] = subRows[i][j]
        }
    }

    return newGrid
}
